// Combine les counts des 7 sources en un seul JSON avec total et warnings
const items = $input.all().map(i => i.json);
const counts = { pubmed: 0, openalex: 0, crossref: 0, semanticscholar: 0, doaj: 0, base: 0, lens: 0, sciencedirect: 0 };
const errors = {};

for (const item of items) {
  const src = item._source;
  if (src && counts[src] !== undefined) {
    counts[src] = item.count || 0;
    if (item.error) errors[src] = item.error;
  }
}

const total = counts.pubmed + counts.openalex + counts.crossref + counts.semanticscholar + counts.doaj + counts.base + counts.lens + counts.sciencedirect;
const warnings = [];

if (total === 0) {
  warnings.push('Aucun resultat trouve sur les 8 bases. Verifiez votre equation.');
}
if (total > 10000) {
  warnings.push('Plus de 10 000 resultats. Le traitement risque de saturer la RAM. Pensez a poser un cap.');
}
if (total > 50000) {
  warnings.push('CRITIQUE : plus de 50 000 resultats. Tres fortement deconseille sans cap strict.');
}
if (Object.keys(errors).length > 0) {
  warnings.push('Erreurs API : ' + JSON.stringify(errors));
}

console.log('Count summary: pubmed=' + counts.pubmed + ' openalex=' + counts.openalex + ' crossref=' + counts.crossref + ' semanticscholar=' + counts.semanticscholar + ' doaj=' + counts.doaj + ' base=' + counts.base + ' lens=' + counts.lens + ' sciencedirect=' + counts.sciencedirect + ' total=' + total);

return [{ json: {
  action: 'count',
  success: true,
  pubmed_count: counts.pubmed,
  openalex_count: counts.openalex,
  crossref_count: counts.crossref,
  semanticscholar_count: counts.semanticscholar,
  doaj_count: counts.doaj,
  base_count: counts.base,
  lens_count: counts.lens,
  sciencedirect_count: counts.sciencedirect,
  total,
  warnings,
  errors
}}];

// MODULE_DELEGATE_SEARCH_v1

// GENERATE NBIB + SAVE FILE
// Format MEDLINE/nbib :
//   TAG - VALUE
//   Article separator : ligne vide
//
// Tags utilises :
//   PMID, PT (publication type), TI, AU, FAU, DP (date), TA (journal abbrev),
//   JT (journal full), AB (abstract), AID (article ID = doi), VI (volume),
//   IP (issue), PG (pages), LID (location ID), OWN (owner), STAT
const fs = require('fs');
const path = require('path');

const allItems = $input.all().map(i => i.json).filter(a => !a._empty);
const inputParams = $('Extract Params').first().json;
const capGlobal = parseInt(inputParams.cap_global) || 0;
const unlimited = inputParams.unlimited === true;

// Apply global cap (apres merge de toutes les sources)
let articles = allItems;
if (!unlimited && capGlobal > 0 && articles.length > capGlobal) {
  console.log(`Apply cap_global ${capGlobal} on ${articles.length} -> ${capGlobal}`);
  articles = articles.slice(0, capGlobal);
}

const counts = { pubmed: 0, openalex: 0, crossref: 0, semanticscholar: 0, doaj: 0, base: 0, lens: 0, sciencedirect: 0 };
for (const a of articles) {
  if (counts[a._source || a.source] !== undefined) counts[a._source || a.source]++;
}

// Format MEDLINE one entry
function fmt(tag, value) {
  if (!value && value !== 0) return '';
  const v = String(value).replace(/\r/g, '').replace(/\n/g, ' ').trim();
  if (!v) return '';
  // MEDLINE format : 4 chars tag, " - ", value, continuation lines indented 6 spaces
  // For simplicity we don't wrap long lines (nbib parsers handle long lines).
  return tag.padEnd(4) + '- ' + v + '\n';
}

function toNbib(a) {
  let out = '';
  // PMID first if available
  if (a.pmid) out += fmt('PMID', a.pmid);
  out += fmt('OWN', 'NLM');
  out += fmt('STAT', 'MEDLINE');
  out += fmt('PT', 'Journal Article');
  // Title
  out += fmt('TI', a.title);
  // Authors
  if (Array.isArray(a.authors)) {
    for (const au of a.authors) {
      if (au) {
        out += fmt('FAU', au);
        // Build AU as "Surname FI" if possible (assume "First Last")
        const parts = au.trim().split(/\s+/);
        if (parts.length >= 2) {
          const last = parts[parts.length - 1];
          const initials = parts.slice(0, -1).map(p => p.charAt(0).toUpperCase()).join('');
          out += fmt('AU', last + ' ' + initials);
        } else {
          out += fmt('AU', au);
        }
      }
    }
  }
  // Journal info
  if (a.journal) {
    out += fmt('JT', a.journal);
    out += fmt('TA', a.journal);
  }
  if (a.volume) out += fmt('VI', a.volume);
  if (a.issue) out += fmt('IP', a.issue);
  if (a.pages) out += fmt('PG', a.pages);
  // Date
  if (a.year) out += fmt('DP', a.year);
  // Abstract
  if (a.abstract) out += fmt('AB', a.abstract);
  // IDs
  if (a.doi) {
    out += fmt('AID', a.doi + ' [doi]');
    out += fmt('LID', a.doi + ' [doi]');
  }
  if (a.openalex_id) out += fmt('LID', a.openalex_id + ' [openalex]');
  // Source tag (custom, mais utile pour traçabilite)
  out += fmt('SO', '[source:' + (a._source || a.source || '') + ']');
  return out + '\n';
}

const nbibContent = articles.map(toNbib).join('');

// Sauvegarde fichier
// output_folder vient du parametre user (ex: /desktop/MaRecherche)
// le volume docker mappe /desktop -> Desktop user
let outputFolder = (inputParams.output_folder || '/desktop').trim();
if (!outputFolder.startsWith('/desktop')) {
  // Securite : forcer dans /desktop pour eviter ecriture hors zone
  outputFolder = '/desktop';
}
try {
  if (!fs.existsSync(outputFolder)) fs.mkdirSync(outputFolder, { recursive: true });
} catch(e) {
  console.log('mkdir error: ' + e.message);
}

const timestamp = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
const filename = 'ultralab-search-' + timestamp + '.nbib';
const fullPath = path.join(outputFolder, filename);

let saveSuccess = false;
let saveError = null;
try {
  fs.writeFileSync(fullPath, nbibContent, 'utf-8');
  saveSuccess = true;
  console.log('NBIB saved: ' + fullPath + ' (' + articles.length + ' articles, ' + nbibContent.length + ' bytes)');
} catch(e) {
  saveError = e.message;
  console.log('NBIB save error: ' + e.message);
}

// METHODS_LOG_v1 - log de reproductibilite (section Methodes d'une revue systematique)
  try {
    var __methods = {
      generated_at: new Date().toISOString(),
      tool: 'UltraLab', module: 'recherche-api',
      nbib_file: filename,
      search: {
        pubmed_equation: inputParams.pubmed_query || '',
        per_base_queries: {
          openalex: inputParams.openalex_query || '', crossref: inputParams.crossref_query || '',
          semanticscholar: inputParams.semanticscholar_query || '', doaj: inputParams.doaj_query || '',
          base: inputParams.base_query || '', lens: inputParams.lens_query || '', sciencedirect: inputParams.sciencedirect_query || ''
        },
        date_range: { start: inputParams.date_start || '', end: inputParams.date_end || '' },
        count_by_source: counts,
        total_after_dedup: articles.length
      }
    };
    fs.writeFileSync(path.join(outputFolder, 'methods-' + timestamp + '.json'), JSON.stringify(__methods, null, 2), 'utf-8');
    console.log('methods.json saved (reproductibilite)');
  } catch (e) { console.log('methods write error: ' + e.message); }

  return [{ json: {
  action: 'search',
  success: saveSuccess,
  file_path: fullPath,
  file_name: filename,
  output_folder: outputFolder,
  bytes: nbibContent.length,
  total_articles: articles.length,
  count_by_source: counts,
  capped: !unlimited && capGlobal > 0 && allItems.length > capGlobal,
  original_total: allItems.length,
  error: saveError
}}];

// Semantic Scholar Count - compte rapide (limit=1, on lit total)
const input = $('Extract Params').first().json;
const query = encodeURIComponent(input.semanticscholar_query || input.openalex_query || input.pubmed_query || input.question || '');
const PROXY = 'http://host.docker.internal:3456';
// SEMANTIC_SCHOLAR_KEY_v1 - cle API optionnelle (x-api-key, appel direct car le proxy ne porte pas les headers)
let __ssKey = '';
try { const __k = await this.helpers.httpRequest({ method: 'GET', url: 'http://host.docker.internal:8080/api/get-secret?field=semanticscholar_api_key', timeout: 5000, json: true }); __ssKey = (__k && __k.value) || ''; } catch (e) {}
if (!query) return [{ json: { _source: 'semanticscholar', count: 0 } }];
try {
  const url = 'https://api.semanticscholar.org/graph/v1/paper/search?query=' + query + '&limit=1';
  const __opts = __ssKey ? { method: 'GET', url: url, headers: { 'x-api-key': __ssKey }, timeout: 30000, json: true }
                         : { method: 'GET', url: PROXY + '?url=' + encodeURIComponent(url), timeout: 30000, json: true };
  const resp = await this.helpers.httpRequest(__opts);
  const count = (resp && resp.total) || 0;
  return [{ json: { _source: 'semanticscholar', count: count } }];
} catch (e) {
  return [{ json: { _source: 'semanticscholar', count: 0, error: e.message } }];
}

// PER_BASE_QUERY_v1
// DOAJ Count
const input = $('Extract Params').first().json;
const query = input.doaj_query || input.openalex_query || input.pubmed_query || input.question || '';
const PROXY = 'http://host.docker.internal:3456';
if (!query) return [{ json: { _source: 'doaj', count: 0 } }];
try {
  const url = 'https://doaj.org/api/search/articles/' + encodeURIComponent(query) + '?pageSize=1';
  const resp = await this.helpers.httpRequest({
    method: 'GET', url: PROXY + '?url=' + encodeURIComponent(url), timeout: 30000, json: true
  });
  return [{ json: { _source: 'doaj', count: (resp && resp.total) || 0 } }];
} catch (e) {
  return [{ json: { _source: 'doaj', count: 0, error: e.message } }];
}

// BASE_IP_TRANSPARENCY_v1
// BASE Count
const input = $('Extract Params').first().json;
const query = input.base_query || input.openalex_query || input.pubmed_query || input.question || '';
const PROXY = 'http://host.docker.internal:3456';
if (!query) return [{ json: { _source: 'base', count: 0 } }];
try {
  const url = 'https://api.base-search.net/cgi-bin/BaseHttpSearchInterface.fcgi?func=PerformSearch&query=' +
              encodeURIComponent(query) + '&hits=1&format=json';
  const resp = await this.helpers.httpRequest({
    method: 'GET', url: PROXY + '?url=' + encodeURIComponent(url), timeout: 30000, json: true
  });
  if (resp && resp.error && /access denied/i.test(resp.error)) {
    return [{ json: { _source: 'base', count: 0, error: 'ip_not_registered' } }];
  }
  const total = (resp && resp.response && resp.response.numFound) || 0;
  return [{ json: { _source: 'base', count: total } }];
} catch (e) {
  return [{ json: { _source: 'base', count: 0, error: e.message } }];
}

// Lens.org Count - necessite cle API
const input = $('Extract Params').first().json;
const query = input.lens_query || input.openalex_query || input.pubmed_query || input.question || '';
if (!query) return [{ json: { _source: 'lens', count: 0 } }];

let apiKey = '';
try {
  const keyResp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://host.docker.internal:8080/api/get-secret?field=lens_api_key',
    timeout: 5000, json: true
  });
  apiKey = (keyResp && keyResp.value) || '';
} catch (e) {}
if (!apiKey) return [{ json: { _source: 'lens', count: 0, error: 'no API key' } }];

try {
  const payload = JSON.stringify({ query: { query_string: { query: query } }, size: 1 });
  const resp = await this.helpers.httpRequest({
    method: 'POST', url: 'https://api.lens.org/scholarly/search',
    body: payload,
    headers: { 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' },
    timeout: 30000, json: true
  });
  return [{ json: { _source: 'lens', count: (resp && resp.total) || 0 } }];
} catch (e) {
  return [{ json: { _source: 'lens', count: 0, error: e.message } }];
}

// ScienceDirect Count - SCIENCEDIRECT_SOURCE_v1 - necessite cle API Elsevier (X-ELS-APIKey)
const input = $('Extract Params').first().json;
const query = input.sciencedirect_query || input.openalex_query || input.pubmed_query || input.question || '';
if (!query) return [{ json: { _source: 'sciencedirect', count: 0 } }];

let apiKey = '', instToken = '';
try {
  const k = await this.helpers.httpRequest({ method: 'GET', url: 'http://host.docker.internal:8080/api/get-secret?field=sciencedirect_api_key', timeout: 5000, json: true });
  apiKey = (k && k.value) || '';
  const t = await this.helpers.httpRequest({ method: 'GET', url: 'http://host.docker.internal:8080/api/get-secret?field=sciencedirect_inst_token', timeout: 5000, json: true });
  instToken = (t && t.value) || '';
} catch (e) {}
if (!apiKey) return [{ json: { _source: 'sciencedirect', count: 0, error: 'no_key' } }];

try {
  const headers = { 'X-ELS-APIKey': apiKey, 'Accept': 'application/json' };
  if (instToken) headers['X-ELS-Insttoken'] = instToken;
  const url = 'https://api.elsevier.com/content/search/sciencedirect?count=1&query=' + encodeURIComponent(query);
  const resp = await this.helpers.httpRequest({ method: 'GET', url: url, headers: headers, timeout: 30000, json: true });
  const sr = (resp && resp['search-results']) || {};
  const total = parseInt(sr['opensearch:totalResults']) || 0;
  return [{ json: { _source: 'sciencedirect', count: total } }];
} catch (e) {
  const msg = (e && e.message) ? e.message : String(e);
  const code = /429/.test(msg) ? 'rate_limited' : (/40[13]/.test(msg) ? 'invalid_key' : 'error');
  console.log('[ScienceDirect Count] error: ' + msg);
  return [{ json: { _source: 'sciencedirect', count: 0, error: code } }];
}
